UPDATE DRFT
   SET DRFT_STTS_CD = #{sttsCd}
 WHERE DRFT_ID = #{drftId}

UPDATE DRFT_PLR
   SET IS_PICK_YN = 'Y'
     , PLR_ID     = #{plrId}
 WHERE DRFT_PLR_ID = #{drftPlrId}

UPDATE DRFT_ORD
   SET PICK_STTS_CD = 'PICKED'
     , DRFT_PLR_ID  = #{drftPlrId}
     , PLR_ID        = #{plrId}
 WHERE DRFT_ID = #{drftId}
   AND PICK_NO  = #{pickNo}

mapper.delete:
DELETE FROM DRFT_BOARD
 WHERE DRFT_ID     = #{drftId}
   AND DRFT_PLR_ID = #{drftPlrId}
   AND TM_ID        = #{tmId}
